package be.schaubroeck.lpb.rkm.rekenmotor.results;

import be.schaubroeck.lpb.rkm.rekenmotor.RekenTijd;
import be.schaubroeck.lpb.rkm.rekenmotor.SleutelGegevens;
import be.schaubroeck.lpb.rkm.rekenmotor.comparator.RekenInfoComparator;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenInfoKey;
import be.schaubroeck.lpb.rkm.rekenmotor.mapkeys.RekenHoofdKey;
import be.schaubroeck.lpb.rkm.rekenmotor.mapkeys.RekenLijnKey;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RekenTools;
import be.schaubroeck.lpb.rkm.rekenmotor.util.TimeTools;
import be.schaubroeck.lpb.tools.Money;
import be.schaubroeck.lpb.tools.Opdracht;
import be.schaubroeck.lpb.tools.RekenBedrag;
import be.schaubroeck.lpb.tools.RekenHoofd;
import be.schaubroeck.lpb.tools.RekenInfo;
import be.schaubroeck.lpb.tools.RekenLijn;
import be.schaubroeck.lpb.tools.RekenOverdracht;
import be.schaubroeck.lpb.tools.ToegepasteTussenkomst;
import be.schaubroeck.lpb.tools.enumtypes.AardRekenelement;
import be.schaubroeck.lpb.tools.enumtypes.LnedefRegBv;
import be.schaubroeck.lpb.tools.enumtypes.RekenBedragType;
import be.schaubroeck.lpb.tools.enumtypes.RekenHoofdBron;
import be.schaubroeck.lpb.tools.enumtypes.Rekengroep;
import be.schaubroeck.lpb.tools.enumtypes.Rekenmodus;
import be.schaubroeck.lpb.tools.jpa.lo.RekenBedragPO;
import be.schaubroeck.lpb.tools.jpa.lo.RekenHoofdPO;
import be.schaubroeck.lpb.tools.jpa.lo.RekenInfoPO;
import be.schaubroeck.lpb.tools.jpa.lo.RekenLijnPO;
import be.schaubroeck.lpb.tools.jpa.lo.RekenOverdrachtPO;
import be.schaubroeck.lpb.tools.jpa.lo.ToegepasteTussenkomstPO;
import com.google.common.collect.ArrayListMultimap;
import com.google.common.collect.ListMultimap;
import org.joda.time.LocalDate;

import java.util.HashSet;
import java.util.List;
import java.util.Map;
import java.util.Set;

public class RekenResultaatUtil {

    public static RekenHoofd maakRekenHoofd(
            Opdracht opdracht, RekenHoofdKey key, Rekenmodus rekenModus, Rekengroep rekenGroep, RekenTijd rekenTijd, int fiscaalJaar, LocalDate beslagDatum,
            boolean vorigKwartaal) {
        LocalDate beginDatum = rekenTijd.beginDatum;

        RekenHoofd rekenHoofd = new RekenHoofdPO();
        rekenHoofd.setOpdracht(opdracht);
        rekenHoofd.setBeginDatum(beginDatum);
        rekenHoofd.setEindDatum(beginDatum.dayOfMonth().withMaximumValue());
        rekenHoofd.setRekenTijdstip(rekenTijd.rekenTijdstip);
        rekenHoofd.setRekenDatum(rekenTijd.rekenDatum);
        rekenHoofd.setBeslagDatum(beslagDatum);
        LocalDate datumJaarKwartaal;
        if (vorigKwartaal) {
            datumJaarKwartaal = TimeTools.bepaalSelectieDatumVorigKwartaalDmfappl(rekenTijd);
        } else {
            datumJaarKwartaal = beginDatum;
        }
        rekenHoofd.setJaar(datumJaarKwartaal.getYear());
        rekenHoofd.setKwartaal(TimeTools.bepaalKwartaal(datumJaarKwartaal));
        rekenHoofd.setFiscaalJaar(fiscaalJaar);
        rekenHoofd.setAchterstal(fiscaalJaar > beginDatum.getYear());
        rekenHoofd.setRekenModus(rekenModus);

        rekenHoofd.setRekenGroep(rekenGroep);
        rekenHoofd.setHoedanigheid(key.getHoedanigheid());
        rekenHoofd.setCategorie(key.getCategorie());
        rekenHoofd.setWerkgeversCategorie(key.getWerkgeversCategorie());
        rekenHoofd.setWerknemersKengetal(key.getWerknemersKengetal());
        rekenHoofd.setPensioenStelsel(key.getPensioenStelsel());
        rekenHoofd.setBron(rekenTijd.isApo ? RekenHoofdBron.APO_REKENMOTOR2 : RekenHoofdBron.REKENMOTOR2);
        return rekenHoofd;
    }

    public static RekenLijn maakRekenLijn(
            RekenLijnKey key, Set<RekenBedrag> rekenBedragen, Set<ToegepasteTussenkomst> toegepasten, Set<RekenInfo> rekenInfos, AardRekenelement typeBoeking) {
        RekenLijn lijn = new RekenLijnPO();
        lijn.setBeginDatum(key.getBeginDatum());
        lijn.setEindDatum(key.getEindDatum());
        lijn.setAardKodeExtensie(key.getAardKodeExtensie());
        lijn.setRegimeBv(key.getRegimeBv());
        lijn.setRekenBedragen(rekenBedragen);
        lijn.setToegepasteTussenkomsten(toegepasten);
        lijn.setRekenInfos(rekenInfos);
        lijn.setReferentieJaar(key.getReferentieJaar());
        lijn.setTypeBoeking(typeBoeking);
        return lijn;
    }

    public static RekenInfo maakRekenInfo(RekenInfoKey key, String info) {
        RekenInfo rekenInfo = new RekenInfoPO();
        rekenInfo.setInfoType(RekenTools.rekenInfoKeyToInfoType(key));
        rekenInfo.setInfo(info);
        return rekenInfo;
    }

    public static RekenInfo maakRekenInfo(RekenInfo old) {
        RekenInfo rekenInfo = new RekenInfoPO();
        rekenInfo.setInfoType(old.getInfoType());
        rekenInfo.setInfo(old.getInfo());
        return rekenInfo;
    }

    public static RekenBedrag maakRekenBedrag(RekenBedragType bedragType, Money bedrag) {
        RekenBedrag rekenBedrag = new RekenBedragPO();
        rekenBedrag.setBedragType(bedragType);
        rekenBedrag.setBedrag(bedrag);
        return rekenBedrag;
    }

    public static ToegepasteTussenkomst maakToegepasteTussenkomst(RekenBedragType bedragType, Money bedrag) {
        ToegepasteTussenkomst toegepast = new ToegepasteTussenkomstPO();
        toegepast.setBedragType(bedragType);
        toegepast.setBedrag(bedrag);
        return toegepast;
    }

    public static RekenOverdracht maakRekenOverdracht(Opdracht opdracht, RekenTijd rekenTijd, LnedefRegBv regimeBv, RekenBedragType bedragType, Money bedrag) {
        LocalDate beginDatum = rekenTijd.beginDatum;
        RekenOverdracht overdracht = new RekenOverdrachtPO();
        overdracht.setOpdracht(opdracht);
        overdracht.setBeginDatum(beginDatum);
        overdracht.setRegimeBv(regimeBv);
        overdracht.setBedragType(bedragType);
        overdracht.setBedrag(bedrag);
        return overdracht;
    }

    public static ListMultimap<Integer, RekenHoofd> mapOpdrachtIdToRekenHoofden(List<RekenHoofd> bestaanden) {
        ListMultimap<Integer, RekenHoofd> map = ArrayListMultimap.create();
        for (RekenHoofd bestaand : bestaanden) {
            map.put(bestaand.getOpdracht().getId(), bestaand);
        }
        return map;
    }

    public static ListMultimap<RekenHoofdKey, SleutelGegevens> mapRekenHoofdKeyToSleutelGegevens(List<SleutelGegevens> gegevensLijst, RekenTijd rekenTijd) {
        ListMultimap<RekenHoofdKey, SleutelGegevens> map = ArrayListMultimap.create();
        for (SleutelGegevens gegevens : gegevensLijst) {
            map.put(new RekenHoofdKey(gegevens, rekenTijd), gegevens);
        }
        return map;
    }

    public static ListMultimap<RekenHoofdKey, RekenHoofd> mapRekenHoofdKeyToRekenHoofden(List<RekenHoofd> hoofden) {
        ListMultimap<RekenHoofdKey, RekenHoofd> map = ArrayListMultimap.create();
        for (RekenHoofd hoofd : hoofden) {
            map.put(new RekenHoofdKey(hoofd), hoofd);
        }
        return map;
    }

    public static Set<ToegepasteTussenkomst> vormToegepasteTussenkomsten(Map<RekenBedragType, Money> nieuwBedragen) {
        Set<ToegepasteTussenkomst> toegepasten = new HashSet<>();
        for (Map.Entry<RekenBedragType, Money> entry : nieuwBedragen.entrySet()) {
            if (entry.getValue().signum() != 0) {
                ToegepasteTussenkomst toegepast = RekenResultaatUtil.maakToegepasteTussenkomst(entry.getKey(), entry.getValue());
                toegepasten.add(toegepast);
            }
        }
        return toegepasten;
    }

    public static Set<RekenInfo> vormRekenInfos(Map<RekenInfoKey, Object> infos) {
        Set<RekenInfo> rekenInfos = RekenInfoComparator.createSortedSet();
        for (Map.Entry<RekenInfoKey, Object> info : infos.entrySet()) {
            if (info.getValue() != null) {
                RekenInfo rekenInfo = RekenResultaatUtil.maakRekenInfo(info.getKey(), RekenTools.toStringRekenInfo(info.getValue()));
                rekenInfos.add(rekenInfo);
            }
        }
        return rekenInfos;
    }
}
